(100, 'Injetoras', 'Lorem ipsum dolor sit amet, consectetur adipiscing elit. In libero neque, sodales a justo eu, vestibulum iaculis ipsum. In pulvinar odio ut lacus lobortis, in consectetur erat luctus. Maecenas tincidunt ex in accumsan vulputate. Maecenas finibus lorem nec augue malesuada, nec convallis ligula lobortis. Pellentesque posuere tincidunt sapien id imperdiet. Nullam volutpat lacus ut mi porta maximus. Vivamus lectus purus, finibus a ligula quis, sodales sodales dolor. Aliquam maximus massa nulla, ut porttitor dolor ultrices at.', 'injetoras'),
(101, 'Lixadeiras', '<p class=\"MsoNormal\"><span style=\"font-size:12.0pt;line-height:107%\">A <b>CECOMATEC </b>oferece diversos modelos de\r\nlixadeira de cinta, para indústrias de fundição, móveis, metalúrgica, serralheria,\r\nrebarbação, desbaste e polimento<o:p></o:p></span></p>\r\n\r\n<p class=\"MsoNormal\"><b><u><span style=\"font-size:12.0pt;line-height:107%\">VANTAGENS NO USO DA LIXADEIRA DE\r\nCINTA INDUSTRIAL EM COMPARAÇÃO À EQUIPAMENTOS COM ABRASIVOS RÍGIDOS:</span></u></b></p><ul><li><span style=\"font-size:15.0pt;line-height:107%\">Melhor\r\nacabamento superficial, eliminando etapas posteriores<o:p></o:p></span></li><li><span style=\"font-size:15.0pt;line-height:107%\">Redução do\r\nnúmero de acidentes, diminuição da vibração e ruído proporcionando maior\r\nsegurança ao operador<o:p></o:p></span></li></ul><p class=\"MsoNormal\">\r\n\r\n\r\n\r\n</p><ul><li><span style=\"font-size:15.0pt;line-height:107%\">Economia\r\ndevido à redução no tempo de processo, pois permite maior remoção de material <o:p></o:p></span></li></ul>', 'lixadeiras'),
(102, 'Corte Canal', '', 'corte-canal'),
(103, 'Fornos', '<p class=\"MsoNormal\">FOCO NO ATENDIMENTO DO PROCESSO DO CLIENTE, FABRICANDO\r\nPRODUTOS DE ALTA DURABILIDADE E TECNOLOGIA AVANÇADA.<o:p></o:p></p>', 'fornos');

