INSERT INTO `produtos` (`id`, `titulo`, `subtitulo`, `id_categoria`, `id_subcategoria`, `caracteristicas`, `video`, `descricao`, `arquivo_pdf`, `slug`, `modelos`) VALUES
(63, 'Injetora tipo C', '', 100, 6, '<table class=\"fr-alternate-rows\" style=\"width: 100%;\"><thead><tr><th colspan=\"2\" style=\"width: 99.9049%; text-align: center;\">Caracter&iacute;sticas principais</th></tr></thead><tbody><tr><td class=\"fr-cell-fixed \" style=\"width: 14.5576%; text-align: left;\">Forma</td><td style=\"width: 85.3473%; text-align: left;\">Forma construtiva tipo &#39;C&#39;, &aacute;rea de trabalho sem obstru&ccedil;&otilde;es, facilitando acesso para troca e fixa&ccedil;&atilde;o de moldes<br></td></tr><tr><td style=\"width: 14.5576%; text-align: left;\">Modelos</td><td style=\"width: 85.3473%; text-align: left;\">Modelos com 01 ou 02 c&eacute;lulas de inje&ccedil;&atilde;o, com controles de fluxo, press&atilde;o e tempo do ciclo inje&ccedil;&otilde;es individuais</td></tr><tr><td style=\"width: 14.5576%; text-align: left;\">Ciclo</td><td style=\"width: 85.3473%; text-align: left;\">Quando o ciclo de inje&ccedil;&atilde;o excede o de extra&ccedil;&atilde;o, no modelo de 02 c&eacute;lulas, pode ser supervisionada por 01 operador, duplicando a efici&ecirc;ncia e reduzindo custos com m&atilde;o de obra</td></tr><tr><td style=\"width: 14.5576%; text-align: left;\">Bico</td><td style=\"width: 85.3473%; text-align: left;\">Inje&ccedil;&atilde;o cera horizontal</td></tr><tr><td style=\"width: 14.5576%; text-align: left;\">Temperatura</td><td style=\"width: 85.3473%; text-align: left;\">Controle em 4 zonas: tanque, ambiente, mangueira, e bico de inje&ccedil;&atilde;o</td></tr><tr><td style=\"width: 14.5576%; text-align: left;\">Sistema de purga</td><td style=\"width: 85.3473%; text-align: left;\">Autom&aacute;tico, substitui a cera para no sistema por cera fresca e homog&ecirc;nea, pra uma &oacute;tima performance na inje&ccedil;&atilde;o</td></tr><tr><td style=\"width: 14.5576%; text-align: left;\">Extra&ccedil;&atilde;o de pe&ccedil;as</td><td style=\"width: 85.3473%; text-align: left;\">Pneum&aacute;tico, com acionamento atrav&eacute;s de pedal</td></tr><tr><td style=\"width: 14.5576%; text-align: left;\">Posi&ccedil;&atilde;o do bico</td><td style=\"width: 85.3473%; text-align: left;\">Ajust&aacute;vel</td></tr><tr><td style=\"width: 14.5576%; text-align: left;\">Seguran&ccedil;a</td><td style=\"width: 85.3473%; text-align: left;\">Comando PLC processo e seguran&ccedil;a integrado, para monitoramento e gerenciamento de fun&ccedil;&otilde;es e dispositivo de seguran&ccedil;a</td></tr><tr><td style=\"width: 14.5576%; text-align: left;\">Interface</td><td style=\"width: 85.3473%; text-align: left;\">Interface de gerenciamento de fun&ccedil;&otilde;es de f&aacute;cil opera&ccedil;&atilde;o</td></tr><tr><td style=\"width: 14.5576%; text-align: left;\">Garantia</td><td class=\"fr-cell-handler \" style=\"width: 85.3473%; text-align: left;\">12 meses</td></tr></tbody></table><p data-f-id=\"pbf\" style=\"text-align: center; font-size: 14px; margin-top: 30px; opacity: 0.65; font-family: sans-serif;\">Powered by <a href=\"https://www.froala.com/wysiwyg-editor?pb=1\" title=\"Froala Editor\">Froala Editor</a></p>', '', 'A CECOMATEC oferece diversos modelos de injetora de cera, para indústrias de Microfusão / Fundição de precisão possibilitando a fabricação dos mais variados modelos de peças em cera, para segmentos automotivo, próteses, válvulas entre outros. \r\nFOCO NO ATENDIMENTO DO PROCESSO DO CLIENTE, FABRICANDO PRODUTOS DE ALTA DURABILIDADE E TECNOLOGIA AVANÇADA.\r\nDependendo do modelo de peça a ser injetado, o projeto da máquina pode ser ajustado, indo de encontro as necessidades de cada cliente.\r\nFABRICAÇÃO NACIONAL:\r\nTotalmente adequada as exigências da norma brasileira de segurança (NR12)\r\nSuporte técnico e assistência nacional, proporcionando menores custos e tempo de parada\r\nFinanciamento facilitado via FINAME e Cartão BNDES.', '', 'injetora-tipo-c', '<table class=\"fr-alternate-rows\" style=\"width: 100%;\"><thead><tr><th colspan=\"2\" style=\"width: 18.078%; text-align: center;\">Modelo 6200</th><th style=\"text-align: center;\">For&ccedil;a fechamento</th><th style=\"text-align: center;\">Reservat&oacute;rio hidr&aacute;ulico</th><th style=\"text-align: center;\">Volume cera inje&ccedil;&atilde;o</th><th style=\"text-align: center;\">Curso fechamento</th><th style=\"text-align: center;\">Dimens&otilde;es entre colunas</th><th style=\"text-align: center;\">Fixa&ccedil;&atilde;o ferramentas</th><th style=\"text-align: center;\">Canais refrigera&ccedil;&atilde;o placas</th><th style=\"text-align: center;\">Reservat&oacute;rio cera</th><th style=\"text-align: center;\">Tens&atilde;o</th></tr></thead><tbody><tr><td rowspan=\"3\" style=\"width: 9.1342%; text-align: center;\">Dupla 02 C&eacute;lulas</td><td style=\"width: 9.0823%; text-align: center;\">6121</td><td style=\"width: 9.0823%; text-align: center;\">12 t</td><td style=\"width: 9.0823%; text-align: center;\">80 L</td><td style=\"width: 9.0823%; text-align: center;\">3 L</td><td style=\"width: 9.0823%; text-align: center;\">470 mm</td><td style=\"width: 9.0823%; text-align: center;\">550(L) X 450(P)<br></td><td rowspan=\"3\" style=\"width: 9.1342%; text-align: center;\">Rasgos &#39;T&#39; 16 mm</td><td rowspan=\"3\" style=\"width: 9.039%; text-align: center;\">Incluso</td><td rowspan=\"3\" style=\"width: 9.1342%; text-align: center;\">150 L</td><td rowspan=\"3\" style=\"width: 9.039%; text-align: center;\">220 ou 380 V</td></tr><tr><td style=\"width: 9.0823%; text-align: center;\">6122</td><td style=\"width: 9.0823%; text-align: center;\">20 t</td><td style=\"width: 9.0823%; text-align: center;\">80 L</td><td style=\"width: 9.0823%; text-align: center;\">6 L</td><td style=\"width: 9.0823%; text-align: center;\">570 mm</td><td style=\"width: 9.0823%; text-align: center;\">650(L) X 500(P)<br></td></tr><tr><td style=\"width: 9.0823%; text-align: center;\">6123</td><td style=\"width: 9.0823%; text-align: center;\">30 t</td><td style=\"width: 9.0823%; text-align: center;\">120 L</td><td style=\"width: 9.0823%; text-align: center;\">9 L</td><td style=\"width: 9.0823%; text-align: center;\">870 mm</td><td style=\"width: 9.0823%; text-align: center;\">800(L) X 600(P)<br></td></tr></tbody></table><p><br></p><table class=\"fr-alternate-rows\" style=\"width: 100%;\"><thead><tr><th colspan=\"2\" style=\"width: 18.078%; text-align: center;\">Modelo 6200</th><th style=\"text-align: center;\">For&ccedil;a fechamento</th><th style=\"text-align: center;\">Reservat&oacute;rio hidr&aacute;ulico</th><th style=\"text-align: center;\">Volume cera inje&ccedil;&atilde;o</th><th style=\"text-align: center;\">Curso fechamento</th><th style=\"text-align: center;\">Dimens&otilde;es entre colunas</th><th style=\"text-align: center;\">Fixa&ccedil;&atilde;o ferramentas</th><th style=\"text-align: center;\">Canais refrigera&ccedil;&atilde;o placas</th><th style=\"text-align: center;\">Reservat&oacute;rio cera</th><th style=\"text-align: center;\">Tens&atilde;o</th></tr></thead><tbody><tr><td rowspan=\"3\" style=\"width: 9.1342%; text-align: center;\">Dupla 02 C&eacute;lulas</td><td style=\"width: 9.0823%; text-align: center;\">6221</td><td style=\"width: 9.0823%; text-align: center;\">12 t</td><td style=\"width: 9.0823%; text-align: center;\">240 L</td><td style=\"width: 9.0823%; text-align: center;\">3 L</td><td style=\"width: 9.0823%; text-align: center;\">470 mm</td><td style=\"width: 9.0823%; text-align: center;\">550(L) X 450(P)<br></td><td rowspan=\"3\" style=\"width: 9.1342%; text-align: center;\">Rasgos &#39;T&#39; 16 mm</td><td rowspan=\"3\" style=\"width: 9.039%; text-align: center;\">Incluso</td><td rowspan=\"3\" style=\"width: 9.1342%; text-align: center;\">150 L</td><td rowspan=\"3\" style=\"width: 9.039%; text-align: center;\">220 ou 380 V</td></tr><tr><td style=\"width: 9.0823%; text-align: center;\">6222</td><td style=\"width: 9.0823%; text-align: center;\">20 t</td><td style=\"width: 9.0823%; text-align: center;\">240 L</td><td style=\"width: 9.0823%; text-align: center;\">6 L</td><td style=\"width: 9.0823%; text-align: center;\">570 mm</td><td style=\"width: 9.0823%; text-align: center;\">650(L) X 500(P)<br></td></tr><tr><td style=\"width: 9.0823%; text-align: center;\">6223</td><td style=\"width: 9.0823%; text-align: center;\">30 t</td><td style=\"width: 9.0823%; text-align: center;\">320 L</td><td style=\"width: 9.0823%; text-align: center;\">9 L</td><td style=\"width: 9.0823%; text-align: center;\">870 mm</td><td style=\"width: 9.0823%; text-align: center;\">800(L) X 600(P)<br></td></tr></tbody></table><p><br></p><table class=\"fr-alternate-rows\" style=\"width: 100%;\"><thead><tr><th style=\"text-align: center;\">Caracter&iacute;sticas opcionais</th></tr></thead><tbody><tr><td style=\"width: 100%; text-align: left;\">No modelo de 02 c&eacute;lulas de inje&ccedil;&atilde;o, pode ser usado reservat&oacute;rio adicional para cera, com capacidade de 150 L, possibilitando uso de ceras de tipos e temperaturas diferentes</td></tr><tr><td style=\"width: 100%; text-align: left;\">Bico inje&ccedil;&atilde;o cera vertical</td></tr></tbody></table><p data-f-id=\"pbf\" style=\"text-align: center; font-size: 14px; margin-top: 30px; opacity: 0.65; font-family: sans-serif;\">Powered by <a href=\"https://www.froala.com/wysiwyg-editor?pb=1\" title=\"Froala Editor\">Froala Editor</a></p>'),
(64, 'Injetora tipo 4 colunas', '', 100, 7, '<table class=\"fr-alternate-rows\" style=\"width: 100%;\"><thead><tr><th colspan=\"2\" style=\"width: 99.9049%; text-align: center;\">Características principais</th></tr></thead><tbody><tr><td style=\"width: 14.5576%; text-align: left;\">Forma</td><td style=\"width: 85.3473%; text-align: left;\">Forma construtiva tipo \'04 colunas\', proporciona melhor fechamento de moldes<br></td></tr><tr><td style=\"width: 14.5576%; text-align: left;\">Modelos</td><td style=\"width: 85.3473%; text-align: left;\">Modelos com 01 ou 02 células de injeção, com controles de fluxo, pressão e tempo do ciclo injeções individuais</td></tr><tr><td style=\"width: 14.5576%; text-align: left;\">Ciclo</td><td style=\"width: 85.3473%; text-align: left;\">Quando o ciclo de injeção excede o de extração, no modelo de 02 células, pode ser supervisionada por 01 operador, duplicando a eficiência e reduzindo custos com mão de obra</td></tr><tr><td style=\"width: 14.5576%; text-align: left;\">Bico</td><td style=\"width: 85.3473%; text-align: left;\">Injeção cera horizontal</td></tr><tr><td style=\"width: 14.5576%; text-align: left;\">Temperatura</td><td style=\"width: 85.3473%; text-align: left;\">Controle em 4 zonas: tanque, ambiente, mangueira, e bico de injeção</td></tr><tr><td style=\"width: 14.5576%; text-align: left;\">Sistema de purga</td><td style=\"width: 85.3473%; text-align: left;\">Automático, substitui a cera para no sistema por cera fresca e homogênea, pra uma ótima performance na injeção</td></tr><tr><td style=\"width: 14.5576%; text-align: left;\">Extração de peças</td><td style=\"width: 85.3473%; text-align: left;\">Pneumático, com acionamento através de pedal</td></tr><tr><td style=\"width: 14.5576%; text-align: left;\">Posição do bico</td><td style=\"width: 85.3473%; text-align: left;\">Ajustável</td></tr><tr><td style=\"width: 14.5576%; text-align: left;\">Segurança</td><td style=\"width: 85.3473%; text-align: left;\">Comando PLC processo 