(8, 'Lixadeira de cinta', '', 'lixadeira-de-cinta', 101),
(9, 'Lixadeiras especiais', '', 'lixadeiras-especiais', 101),
(10, 'Forno Mufla', '<p class=\"MsoNormal\">Forno industrial em diversos tamanhos e temperaturas. O\r\nforno mufla é similar a uma estufa, utilizado principalmente em processos\r\nlaboratoriais, quando se necessita de altas temperaturas para calcinação de\r\nsubstâncias para análises metalográficas e testes em indústrias de fundição,\r\nmóveis, plásticos, metalurgia entre outros.<o:p></o:p></p>', 'forno-mufla', 103),
(11, 'Normalização', '<p style=\"\"><span style=\"line-height: 107%;\">Forno industrial em diversos tamanhos e temperaturas. O forno\r\nde tratamento térmico normalização é utilizado para deixar o material em um\r\nestado normal, ou seja, com ausência de tensões internas e até mesmo fazer a\r\ndistribuição de carbono. Utilizado em indústrias de fundição, móveis,\r\nplásticos, metalurgia entre outros.<span style=\"font-size: 9pt;\"><o:p></o:p></span></span></p>', 'normalizacao', 103),
(12, 'Calcinação', '<p class=\"MsoNormal\" style=\"\"><span style=\"line-height: 107%;\">Forno industrial para calcinação em diversos modelos. O forno\r\nde calcinação é utilizado para calcinação de cachos cerâmicos. Utilizado em\r\nindústrias Microfusão / Fundição de precisão, <span style=\"font-size: 9pt;\"><o:p></o:p></span></span></p>', 'calcinacao', 103);

